const input = $input.first().json;
const body = input.body || {};

if (!body.token) {
  return [{ json: { error: 'Token is required', statusCode: 401, valid: false } }];
}

if (!body.vendor_id) {
  return [{ json: { error: 'vendor_id is required', statusCode: 400, valid: false } }];
}

try {
  const parts = body.token.split('.');
  if (parts.length !== 3) {
    return [{ json: { error: 'Invalid token format', statusCode: 401, valid: false } }];
  }

  let payload = parts[1].replace(/-/g, '+').replace(/_/g, '/');
  while (payload.length % 4) payload += '=';
  const decoded = JSON.parse(Buffer.from(payload, 'base64').toString('utf8'));

  if (!decoded.user_id) {
    return [{ json: { error: 'Invalid token: missing user_id', statusCode: 401, valid: false } }];
  }

  if (decoded.exp && decoded.exp < Math.floor(Date.now() / 1000)) {
    return [{ json: { error: 'Token expired', statusCode: 401, valid: false } }];
  }

  // Build update fields - only include provided fields
  const allowedFields = ['name', 'company', 'source', 'source_url', 'source_api_key', 'source_api_secret', 'marketplace_id', 'marketplace_api_key', 'marketplace_url', 'sync_interval_hours', 'sync_status', 'config'];
  const updateData = {};
  let credentialsChanged = false;
  const credentialFields = ['source', 'source_url', 'source_api_key', 'source_api_secret'];

  for (const field of allowedFields) {
    if (body[field] !== undefined) {
      updateData[field] = body[field];
      if (credentialFields.includes(field)) {
        credentialsChanged = true;
      }
    }
  }

  if (Object.keys(updateData).length === 0) {
    return [{ json: { error: 'No fields to update', statusCode: 400, valid: false } }];
  }

  updateData.updated_at = new Date().toISOString();

  return [{ json: { valid: true, user_id: decoded.user_id, vendor_id: body.vendor_id, updateData, credentialsChanged } }];
} catch (e) {
  return [{ json: { error: 'Token decode failed: ' + e.message, statusCode: 401, valid: false } }];
}

const result = $input.first().json;
const vendors = Array.isArray(result) ? result : [result];

if (!vendors.length || !vendors[0].id) {
  return [{ json: { owned: false, error: 'Vendor not found or access denied', statusCode: 404 } }];
}

const prevData = $('Verify Token & Extract').first().json;

return [{ json: { owned: true, existingVendor: vendors[0], updateData: prevData.updateData, vendor_id: prevData.vendor_id, user_id: prevData.user_id, credentialsChanged: prevData.credentialsChanged } }];

const patchResult = $input.first().json;
const vendor = Array.isArray(patchResult) ? patchResult[0] : patchResult;

const prevData = $('Check Ownership').first().json;
const credentialsChanged = prevData.credentialsChanged;

if (credentialsChanged && vendor.source_url && vendor.source_api_key) {
  // Re-test connection with updated credentials
  const source = vendor.source;
  const sourceUrl = vendor.source_url;
  const apiKey = vendor.source_api_key;
  const apiSecret = vendor.source_api_secret;

  let connectionTest = 'skipped';
  let testError = null;

  try {
    let url, headers;

    if (source === 'shopify') {
      const cleanUrl = sourceUrl.replace(/\/+$/, '');
      url = `${cleanUrl}/admin/api/2024-01/shop.json`;
      headers = { 'X-Shopify-Access-Token': apiKey };
    } else if (source === 'woocommerce') {
      const cleanUrl = sourceUrl.replace(/\/+$/, '');
      url = `${cleanUrl}/wp-json/wc/v3/system_status`;
      const basicAuth = Buffer.from(`${apiKey}:${apiSecret}`).toString('base64');
      headers = { 'Authorization': `Basic ${basicAuth}` };
    } else if (source === 'prestashop') {
      const cleanUrl = sourceUrl.replace(/\/+$/, '');
      url = `${cleanUrl}/api/products?display=full&limit=1`;
      const basicAuth = Buffer.from(`${apiKey}:`).toString('base64');
      headers = { 'Authorization': `Basic ${basicAuth}` };
    } else if (source === 'api') {
      url = sourceUrl;
      headers = { 'Authorization': `Bearer ${apiKey}` };
    }

    if (url) {
      const response = await fetch(url, {
        method: 'GET',
        headers,
        signal: AbortSignal.timeout(10000)
      });

      connectionTest = response.ok ? 'ok' : 'failed';
      if (!response.ok) {
        testError = `HTTP ${response.status}: ${response.statusText}`;
      }
    }
  } catch (e) {
    connectionTest = 'failed';
    testError = e.message;
  }

  return [{ json: { success: true, vendor, connection_retest: connectionTest, connection_error: testError || undefined } }];
}

return [{ json: { success: true, vendor } }];
